Index: bench-targets/cli-flags/src/parseArgs.mjs
===================================================================
--- bench-targets/cli-flags/src/parseArgs.mjs	
+++ bench-targets/cli-flags/src/parseArgs.mjs	
@@ -1,9 +1,31 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+  for (let i = 0; i < argv.length; i += 1) {
+    const arg = argv[i]
+    if (arg.startsWith('--') && !arg.includes('=')) {
+      if (arg === '--help') {
+        result._.push(arg)
+      }
+      else if ((i < argv.length - 1) && !argv[i + 1].startsWith('--') && !argv[i + 1].startsWith('.')) {
+        result[arg.slice(2)] = argv[i + 1]
+        i += 1
+      }
+      else {
+        result[arg.slice(2)] = true
+      }
+    }
+    else if ((arg.includes('=') && !arg.startsWith('--help')) || arg.startsWith('--debug=')) {
+      if (!argv[i + 1]?.startsWith('--') && !argv[i + 1]?.startsWith('.') && arg.includes('=')) {
+        const idx = arg.indexOf('=')
+        result[arg.slice(2, idx)] = arg.slice(idx + 1)
+      }
+      else if (!arg.includes('=')) {
+        result[arg.slice(2)] = true
+      }
+    }
+    else {
+      result._.push(arg)
+    }
   }
   return result
 }

